import numpy as np

def transform(inp_grid):
    n = len(inp_grid)
    m = len(inp_grid[0])
    out_grid = np.zeros((n, m), dtype=int)

    for i in range(n):
        for j in range(m):
            if inp_grid[i][j] == 7:
                # Place the 7s in a cross centered at (i, j) within bounds
                if i - j >= 0:
                    out_grid[i - j][0] = 7
                if i + j < n:
                    out_grid[i + j][m - 1] = 7
                if i - j + (m - 1) >= 0:
                    out_grid[i - j + (m - 1)][m - 1] = 7
                if i + j - (m - 1) < n:
                    out_grid[i + j - (m - 1)][0] = 7

    return out_grid.tolist()

test_input = [
    [7, 0, 0],
    [0, 0, 0],
    [0, 0, 0]
]

output = transform(test_input)
output
